const data = items[0].json.data;
const secoesMap = {}; // Balde para agrupar produtos por seção

const regexTitulo = /"title":"(.*?)"/g;
let match;

while ((match = regexTitulo.exec(data)) !== null) {
    const titulo = match[1];
    const inicio = Math.max(0, match.index - 500);
    const fim = Math.min(data.length, match.index + 1200);
    const pedacoTexto = data.substring(inicio, fim);

    const matchLink = pedacoTexto.match(/"permalink":"(.*?)"/);
    if (!matchLink) continue;

    const linkFinal = matchLink[1].replace(/\\u002F/g, '/');

    // FILTRO: Ignora links de menus e listas de "mais-vendidos" (os que geram o "Geral")
    if (linkFinal.includes('/mais-vendidos/') || titulo.includes("Preferências de cookies")) continue;

    // Identifica a Seção via campanha
    let secaoIdentificada = "";
    const matchCampanha = linkFinal.match(/c_campaign=([^&]+)/);

    if (matchCampanha) {
        secaoIdentificada = matchCampanha[1].replace(/-/g, ' ');
        secaoIdentificada = secaoIdentificada.charAt(0).toUpperCase() + secaoIdentificada.slice(1);
    } else {
        // Se não tem campanha no link, provavelmente é um link institucional ou menu
        continue; 
    }

    if (!secoesMap[secaoIdentificada]) {
        secoesMap[secaoIdentificada] = [];
    }

    // Limite de 10 por seção
    if (secoesMap[secaoIdentificada].length >= 10) continue;

    const matchPreco = pedacoTexto.match(/"price":([\d.]+)/);
    const matchFoto = pedacoTexto.match(/"thumbnail":"(.*?)"/);

    let precoFormatado = matchPreco ? 
        parseFloat(matchPreco[1]).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }) : 
        "Sob consulta";

    const fotoFinal = matchFoto ? matchFoto[1].replace(/\\u002F/g, '/') : "Sem foto";

    secoesMap[secaoIdentificada].push({
        secao: secaoIdentificada,
        produto: titulo,
        preco: precoFormatado,
        foto: fotoFinal,
        link: linkFinal
    });
}

// ORGANIZAÇÃO FINAL
const resultadosFinais = [];
// Corrigido de 'em' para 'in'
for (const secao in secoesMap) {
    secoesMap[secao].forEach((item, index) => {
        resultadosFinais.push({
            json: {
                ranking_na_secao: index + 1,
                ...item
            }
        });
    });
}

return resultadosFinais;

// ============================================================
// Amazon Best Sellers — Extrator Avançado (v2.0)
// n8n Code Node | Melhora: Departamentos, Rankings e Imagens
// ============================================================

const html = items[0].json.data;

if (!html) {
  throw new Error('Nenhum HTML recebido. Verifique o nó anterior.');
}

const products = [];

/**
 * 1. Divide o HTML em blocos por categoria.
 * Procura pelo cabeçalho "Mais Vendidos em [NOME]" e pega o conteúdo até a próxima seção.
 */
const sectionRegex = /<h2[^>]*class="[^"]*a-carousel-heading[^"]*"[^>]*>Mais Vendidos em ([^<]+)<\/h2>([\s\S]*?)(?=<h2[^>]*class="[^"]*a-carousel-heading|$)/g;

let sectionMatch;
while ((sectionMatch = sectionRegex.exec(html)) !== null) {
  const categoryName = sectionMatch[1].trim();
  const sectionHtml = sectionMatch[2];

  /**
   * 2. Extrai os cards de produtos dentro desta seção específica.
   * Regex atualizado para incluir a captura da imagem (src).
   */
  const cardRegex = /data-asin="([^"]+)"[\s\S]*?zg-bdg-text[^>]*>#(\d+)<\/span[\s\S]*?<img[^>]*src="([^"]+)"[\s\S]*?p13n-sc-line-clamp[^>]*>([\s\S]*?)<\/div[\s\S]*?p13n-sc-price[^>]*>([\s\S]*?)<\/span/g;

  let cardMatch;
  while ((cardMatch = cardRegex.exec(sectionHtml)) !== null) {
    const asin     = cardMatch[1];
    const ranking  = parseInt(cardMatch[2], 10);
    const imageUrl = cardMatch[3];
    const rawName  = cardMatch[4];
    const rawPrice = cardMatch[5];

    // Limpeza de Nome
    const name = rawName
      .replace(/<[^>]+>/g, '')
      .replace(/\s+/g, ' ')
      .trim();

    // Limpeza e normalização do preço (Mantendo sua lógica original)
    const priceStr = rawPrice.replace(/<[^>]+>/g, '').trim();
    const priceNum = parseFloat(
      priceStr
        .replace(/R\$\s*/g, '')
        .replace(/\./g, '')
        .replace(/,/g, '.')
    ) || null;

    const url = `https://www.amazon.com.br/dp/${asin}`;

    // Adiciona o produto garantindo que o ranking está atrelado a esta categoria
    products.push({
      ranking,
      category: categoryName,
      name,
      price: priceNum,
      price_raw: priceStr,
      image: imageUrl,
      asin,
      url,
      scraped_at: new Date().toISOString()
    });
  }
}

// 3. Ordenação final para garantir organização no n8n
products.sort((a, b) => a.category.localeCompare(b.category) || a.ranking - b.ranking);

// 4. Retorna como itens individuais
return products.map(p => ({ json: p }));

