function sha256(ascii) {
  function rightRotate(value, amount) {
    return (value >>> amount) | (value << (32 - amount));
  }
  var mathPow = Math.pow;
  var maxWord = mathPow(2, 32);
  var i, j;
  var result = '';
  var words = [];
  var asciiBitLength = ascii.length * 8;
  var hash = sha256.h = sha256.h || [];
  var k = sha256.k = sha256.k || [];
  var primeCounter = k.length;
  var isComposite = {};
  for (var candidate = 2; primeCounter < 64; candidate++) {
    if (!isComposite[candidate]) {
      for (i = 0; i < 313; i += candidate) isComposite[i] = candidate;
      hash[primeCounter] = (mathPow(candidate, .5) * maxWord) | 0;
      k[primeCounter++] = (mathPow(candidate, 1/3) * maxWord) | 0;
    }
  }
  ascii += '\x80';
  while (ascii.length % 64 - 56) ascii += '\x00';
  for (i = 0; i < ascii.length; i++) {
    j = ascii.charCodeAt(i);
    words[i >> 2] |= j << ((3 - i) % 4 * 8);
  }
  words[words.length] = ((asciiBitLength / maxWord) | 0);
  words[words.length] = asciiBitLength;
  for (j = 0; j < words.length;) {
    var w = words.slice(j, j += 16);
    var oldHash = hash.slice(0);
    hash = hash.slice(0, 8);
    for (i = 0; i < 64; i++) {
      var w15 = w[i - 15], w2 = w[i - 2];
      var a = hash[0], e = hash[4];
      var temp1 = hash[7]
        + (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25))
        + ((e & hash[5]) ^ (~e & hash[6]))
        + k[i]
        + (w[i] = (i < 16) ? w[i] : (
            w[i - 16]
            + (rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3))
            + w[i - 7]
            + (rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10))
          ) | 0
        );
      var temp2 = (rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22))
        + ((a & hash[1]) ^ (a & hash[2]) ^ (hash[1] & hash[2]));
      hash = [(temp1 + temp2) | 0].concat(hash);
      hash[4] = (hash[4] + temp1) | 0;
      hash.length = 8;
    }
    hash = hash.map(function(a, i) { return (a + oldHash[i]) | 0; });
  }
  for (i = 0; i < 8; i++) {
    for (j = 3; j + 1; j--) {
      var b = (hash[i] >> (j * 8)) & 255;
      result += ((b < 16) ? 0 : '') + b.toString(16);
    }
  }
  return result;
}

const appId     = '18362700399';
const secret    = 'NQQN52SGLUWOQS2N4KKNOM56JGJFJ4P5';
const timestamp = Math.floor(Date.now() / 1000).toString();

// Query SEM keyword (campo opcional) — elimina o problema de aspas escapadas
// JSON.stringify garante que o body aqui = body enviado pelo HTTP Request
const body = JSON.stringify({
  query: '{productOfferV2(listType:0,sortType:2,page:1,limit:50){nodes{itemId productName productLink offerLink imageUrl priceMin priceMax sales ratingStar commissionRate shopName shopId}pageInfo{page limit hasNextPage}}}'
});

const toSign    = appId + timestamp + body + secret;
const signature = sha256(toSign);
const authHeader = `SHA256 Credential=${appId}, Timestamp=${timestamp}, Signature=${signature}`;

return [{ json: { authHeader, body } }];

const response = items[0].json;
const nodes = response?.data?.productOfferV2?.nodes || [];

if (nodes.length === 0) {
  return [{ json: {
    erro: true,
    mensagem: 'Nenhum produto retornado.',
    raw: JSON.stringify(response).substring(0, 500)
  }}];
}

return nodes.map((p, index) => ({
  json: {
    ranking: index + 1,
    category: 'Mais Vendidos',
    name: p.productName,
    // CORREÇÃO: Removida a divisão por 100000 pois o valor já vem como string decimal
    price: parseFloat(p.priceMin).toFixed(2), 
    image: p.imageUrl,
    itemId: p.itemId,
    shopId: p.shopId,
    shopName: p.shopName,
    commissionRate: p.commissionRate,
    sales: p.sales,
    ratingStar: p.ratingStar,
    url: p.offerLink || p.productLink,
    scraped_at: new Date().toISOString()
  }
}));
